sql:
SELECT name 
FROM companies 
WHERE revenue > (SELECT AVG(revenue) FROM companies);

external_knowledge:
'Tech firms' refers to companies in the technology industry;
'a larger-than-average team size' means the average number of employees is greater than the overall average number of employees across all companies;
'more dough than their peers' means the revenue is higher than the average revenue across all companies;

sql:
SELECT name, city, revenue
FROM companies
WHERE name LIKE '%Company%' AND city = 'New York' AND revenue > 100000;

SELECT company_id, revenue
FROM revenues
WHERE year = 2022 AND revenue > 200000;

